import requests

headers = {'Authorization': 'Bearer <your API token>'}
uri = f'https://coda.io/apis/admin/v1/organizations/<your organization id>/docs/<doc ID>/acl/permissions'
payload = {
  'access': 'write',
  'principal': {
    'type': 'email',
    'email': 'foo@bar.com'
  },
}
res = requests.post(uri, headers=headers, json=payload)

# => Grant 'foo@bar.com' write access to the doc and send a share notification email

